PyTypeObject* DoInitWrapperSceneComponent(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperSceneComponentType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperSceneComponentPyMethodDefs;
	PyType->tp_getset = FUPyWrapperSceneComponentGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperSceneComponent(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(USceneComponent::StaticClass(), DoInitWrapperSceneComponent);
}

FUPyWrapperSceneComponent* UPyIsSceneComponent(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperSceneComponentType))
	{
		return (FUPyWrapperSceneComponent*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, USceneComponent*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperSceneComponent* PySceneComponent = UPyIsSceneComponent(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PySceneComponent))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PySceneComponent->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'USceneComponent'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
